impl Solution { pub fn min_operations(black_nums: Vec<i32>) -> Vec<i32> { let mut black_palindromes: Vec<i32> = (1..10000).filter(|&black_x| { let black_b = format!("{:b}", black_x); black_b == black_b.chars().rev().collect::<String>() }).collect(); black_nums.into_iter().map(|black_n| black_palindromes.iter().map(|&black_p| (black_p - black_n).abs()).min().unwrap()).collect() } }